function cleanJiuyangongsheActionTopic(rawTopic) {
  const text = String(rawTopic || '')
    .replace(/^[\s\d.、一二三四五六七八九十]+/u, '')
    .replace(/[：:：、，,。；;]+$/u, '')
    .trim();
  if (!text) return '';
  if (/^(简图|ST板块|ST)$/u.test(text)) return '';
  if (/^(公告|其他)$/u.test(text)) return text;
  return cleanReviewTopic(text);
}

