// getBoards: 读三类型(东财6/同花顺5/KPL7)当天快照里的板块+指标，合并下发
// 策略页 QI 龙头：从快照 cardData(zt10 含主次数 ztCount + gain10/gain30) 按 QI 口径
// (近10日主次数≥2 且 主次数/涨幅均居板块前列) 算每板块 10日/30日 QI 龙头，与看板 QI 同口径
function strategyQiRank(rows, valOf) {
  const m = new Map();
  [...(Array.isArray(rows) ? rows : [])]
    .map(r => ({ code: String(r?.code || ''), name: String(r?.name || ''), v: Number(valOf(r)) }))
    .filter(r => r.code && Number.isFinite(r.v))
    .sort((a, b) => b.v - a.v)
    .forEach((r, i) => { if (!m.has(r.code)) m.set(r.code, { rank: i + 1, v: r.v, name: r.name }); });
  return m;
}
function strategyPickQi(countMap, gainMap, totalByCode) {
  const K = 5, MIN_COUNT = 2, MAX = 3;
  const out = [];
  for (const [code, c] of countMap) {
    const g = gainMap.get(code);
    if (!g) continue;
    if (c.rank <= K && g.rank <= K && c.v >= MIN_COUNT && g.v > 0) out.push({ code, name: c.name || g.name, score: c.rank + g.rank, count: c.v, gain: g.v, total: Number(totalByCode && totalByCode.get(code)) });
  }
  out.sort((a, b) => a.score - b.score);
  // 带上 主次数(count)/总涨停次数(total)/窗口涨幅(gain)/综合名次(score)，供 QI 龙头聚合算战绩/引领；板块卡只用 code/name，多余字段无害
  return out.slice(0, MAX).map(o => ({ code: o.code, name: o.name, count: o.count, total: Number.isFinite(o.total) ? o.total : o.count, gain: Number(o.gain), score: o.score }));
}
function computeBoardQiLeaders(card) {
  if (!card) return null;
  const countMap = strategyQiRank(card.zt10, r => r.ztCount);
  const totalByCode = new Map();
  for (const r of (Array.isArray(card.zt10) ? card.zt10 : [])) {
    const c = String(r?.code || '');
    if (c && !totalByCode.has(c)) totalByCode.set(c, Number(r?.totalCount ?? r?.ztCount));
  }
  const qi10 = strategyPickQi(countMap, strategyQiRank(card.gain10, r => r.gain), totalByCode);
  const qi30 = strategyPickQi(countMap, strategyQiRank(card.gain30, r => r.gain), totalByCode);
  return (qi10.length || qi30.length) ? { qi10, qi30 } : null;
}
async function strategySnapshotDayHasSnap(d) {
  // Codex #88 点3:策略日可用性只按策略来源集(东财6/同花顺5)判断——仅有 KPL(7) 快照的日期
  // 对策略页是「空板日」,不能算可用,否则会选到 zs5/zs6 缺失、策略板块为空的日子。
  for (const z of STRATEGY_ZS_TYPES) { try { await fs.access(snapshotPath(d, String(z))); return true; } catch {} }
  return false;
}
// 请求日(通常=今天盘中、快照15:30才生成)无快照时，回退到最近一个有快照的交易日，避免策略页空白
async function resolveStrategySnapshotDay(day) {
  if (await strategySnapshotDayHasSnap(day)) return day;
  const apiKey = await readSavedApiKey().catch(() => '');
  const td = await getRecentTradingDays(day, apiKey, 15).catch(() => []);
  for (let i = td.length - 1; i >= 0; i--) {
    if (String(td[i]) === String(day)) continue;
    if (await strategySnapshotDayHasSnap(td[i])) return td[i];
  }
  return day;
}
// 列出某交易日「之前」最近一个有快照的交易日，用于「今日新晋 QI」对比
async function prevStrategySnapshotDay(useDay) {
  try {
    const dir = path.join(SNAPSHOT_DIR, '6');
    const files = await fs.readdir(dir);
    const days = files
      .map(f => (/^(\d{4}-\d{2}-\d{2})\.json$/.exec(f) || [])[1])
      .filter(Boolean)
      .filter(d => String(d) < String(useDay))
      .sort();
    return days.length ? days[days.length - 1] : '';
  } catch { return ''; }
}
// 收集某快照日「全部板块」的 QI 龙头代码集合（10日∪30日），用于新晋对比
async function collectStrategyQiCodes(snapDay) {
  const set = new Set();
  for (const zsType of STRATEGY_ZS_TYPES) {   // Owner 2026-07-15:策略只用东财+同花顺,剔除 KPL(7)
    try {
      const payload = JSON.parse(await fs.readFile(snapshotPath(snapDay, String(zsType)), 'utf8'));
      const cardData = payload?.cardData || {};
      for (const b of (Array.isArray(payload?.boards) ? payload.boards : [])) {
        const plateId = String(b?.plateId ?? b?.id ?? b?.code ?? '');
        const ql = computeBoardQiLeaders(cardData[plateId]);
        if (ql) for (const e of [...(ql.qi10 || []), ...(ql.qi30 || [])]) set.add(String(e.code));
      }
    } catch {}
  }
  return set;
}

// 策略页资金口径：东财只使用 f66「超大单净流入」；今日实时仍保留 f62「主力净流入」。
// 历史快照在该字段上线前只有 f62，允许读取但必须携带 legacy 标记，前端不得误称为超大单。
function strategyBoardFundFlowForSource(board, zsType, options = {}) {
  const source = Number(zsType);
  if (source === 6) {
    const superLarge = numOrNull(board?.superLargeNetInflow);
    if (superLarge != null) {
      return {
        value: superLarge,
        metric: 'eastmoney-super-large-net-inflow',
        legacy: false,
      };
    }
    const legacyValue = options.allowLegacyEastmoney
      ? numOrNull(board?.netInflow ?? board?.mainInflow ?? board?.inflow)
      : null;
    return {
      value: legacyValue,
      metric: legacyValue == null
        ? 'eastmoney-super-large-net-inflow'
        : 'eastmoney-main-net-inflow-legacy',
      legacy: legacyValue != null,
    };
  }
  return {
    value: numOrNull(board?.netInflow ?? board?.mainInflow ?? board?.inflow),
    metric: source === 5 ? 'ths-net-inflow' : 'source-net-inflow',
    legacy: false,
  };
}

async function getStrategyBoardsForDay(day, options = {}) {
  const requestedDay = isoFromCompactDate(day);
  const allowFallback = options.allowFallback !== false;
  const useDay = allowFallback ? await resolveStrategySnapshotDay(requestedDay) : requestedDay;
  const out = [];
  const includeKeys = new Set((Array.isArray(options.includeBoards) ? options.includeBoards : [])
    .map((b) => `${String(b?.zsType ?? '')}:${String(b?.plateId ?? '').trim()}`)
    .filter((key) => !key.endsWith(':')));
  const shouldHydrateIncluded = (board, zsType) => includeKeys.has(`${String(zsType)}:${String(board?.plateId ?? '')}`);
  for (const zsType of STRATEGY_ZS_TYPES) {   // Owner 2026-07-15:剔除 KPL(7),策略只用东财+同花顺
    let hidden; try { hidden = await getPermanentHiddenSet(zsType); } catch { hidden = new Set(); }
    try {
      const payload = JSON.parse(await fs.readFile(snapshotPath(useDay, String(zsType)), 'utf8'));
      const cardData = payload?.cardData || {};
      // P1:优先信任快照 payload 内部声明的日期,而非仅凭文件名 useDay。
      // 文件内部 day 与 useDay 不一致时以内部声明为准,交给上层按跨日剔除。
      const declaredDay = isoFromCompactDate(payload?.day || '') || useDay;
      for (const b of (Array.isArray(payload?.boards) ? payload.boards : [])) {
        const plateId = String(b?.plateId ?? b?.id ?? b?.code ?? '');
        if (!plateId) continue;
        if (hidden.has(plateId)) continue;   // 看板永久删除(删两次)的板块,策略候选/强势板块也排除
        const fundFlow = strategyBoardFundFlowForSource(b, zsType, { allowLegacyEastmoney: true });
        out.push({
          plateId,
          name: String(b?.name ?? b?.plateName ?? ''),
          gainPct: Number(b?.gainPct ?? b?.gain ?? NaN),
          ztCount: Number(b?.ztCount ?? b?.zt ?? NaN),
          netInflow: fundFlow.value,
          netInflowMetric: fundFlow.metric,
          netInflowLegacy: fundFlow.legacy,
          zsType,
          qiLeaders: computeBoardQiLeaders(cardData[plateId]),
          sourceDay: declaredDay,  // P1 防跨日污染:优先 payload 内部声明日期,回退/错标时 ≠ requestedDay
          sourceKind: 'snapshot',
        });
      }
    } catch {}
  }
  if (options.liveIfMissing && isChinaMarketTradingDay(requestedDay) && (!out.length || includeKeys.size)) {
    const apiKey = await readSavedApiKey().catch(() => '');
    if (apiKey) {
      const liveOutByKey = new Map(out.map(board => [`${String(board?.zsType ?? '')}:${String(board?.plateId ?? '')}`, board]));
      for (const zsType of STRATEGY_ZS_TYPES) {   // Owner 2026-07-15:剔除 KPL(7)
        const scopedPrefix = `${String(zsType)}:`;
        const includedForType = [...includeKeys].filter(key => key.startsWith(scopedPrefix));
        if (out.length && includeKeys.size && !includedForType.length) continue;
        let hidden; try { hidden = await getPermanentHiddenSet(zsType); } catch { hidden = new Set(); }
        try {
          const liveBoards = await fetchBoardRankingForSnapshot(String(zsType), apiKey, {
            count: Number(options.liveRankCount || 0) || 500,
          });
          for (const raw of liveBoards) {
            const plateId = String(raw?.plateId ?? raw?.id ?? raw?.code ?? '');
            if (!plateId || hidden.has(plateId)) continue;
            const liveKey = `${String(zsType)}:${plateId}`;
            if (out.length && includeKeys.size && !includeKeys.has(liveKey)) continue;
            let board = { ...raw, plateId };
            if (shouldHydrateIncluded(board, zsType)) {
              const hydrated = await hydrateBoardForSnapshot({ ...board }, apiKey, String(zsType), requestedDay).catch(() => null);
              if (hydrated?.board) board = { ...board, ...hydrated.board };
            }
            const fundFlow = strategyBoardFundFlowForSource(board, zsType);
            const liveItem = {
              plateId,
              name: String(board?.name ?? board?.plateName ?? ''),
              gainPct: Number(board?.gainPct ?? board?.gain ?? NaN),
              ztCount: Number(board?.ztCount ?? board?.zt ?? NaN),
              netInflow: fundFlow.value,
              netInflowMetric: fundFlow.metric,
              netInflowLegacy: fundFlow.legacy,
              zsType,
              qiLeaders: null,
              sourceDay: requestedDay,   // P1:实时行情属于请求日本身,非回退
              sourceKind: 'live',
            };
            const existing = liveOutByKey.get(liveKey);
            if (existing) {
              if (liveItem.name) existing.name = liveItem.name;
              if (Number.isFinite(liveItem.gainPct)) existing.gainPct = liveItem.gainPct;
              if (Number.isFinite(liveItem.ztCount)) existing.ztCount = liveItem.ztCount;
              if (Number.isFinite(liveItem.netInflow)) {
                existing.netInflow = liveItem.netInflow;
                existing.netInflowMetric = liveItem.netInflowMetric;
                existing.netInflowLegacy = liveItem.netInflowLegacy;
              }
            } else {
              out.push(liveItem);
              liveOutByKey.set(liveKey, liveItem);
            }
          }
        } catch {}
      }
    }
  }
  return out;
}

async function hydrateStrategyLiveBoardsForMembers(boards, apiKey, zsType, day) {
  const list = Array.isArray(boards) ? boards : [];
  const cardData = {};
  const hydratedBoards = await mapLimit(list, 8, async raw => {
    const plateId = String(raw?.plateId ?? raw?.id ?? raw?.code ?? '');
    if (!plateId) return raw;
    const board = { ...raw, plateId };
    let hydrateTimedOut = false;
    const hydrated = await Promise.race([
      hydrateBoardForSnapshot({ ...board }, apiKey, String(zsType), day).catch(err => {
        strategyMainlineDiagNoteRead(`board-hydrate ${plateId} zs${zsType}`, err);   // 七审:成分补水失败不再空吞
        return null;
      }),
      new Promise(resolve => setTimeout(() => { hydrateTimedOut = true; resolve(null); }, STRATEGY_MAINLINE_LIVE_HYDRATE_TIMEOUT_MS)),
    ]);
    // 七审:补水超时兜底如实记入诊断上下文(稳定 label),不把半结果当完整。
    if (hydrateTimedOut) strategyMainlineDiagNoteTimeout(`board-hydrate ${plateId} zs${zsType}`);
    if (!hydrated?.board) return board;
    if (hydrated.cardData) cardData[plateId] = hydrated.cardData;
    return { ...board, ...hydrated.board };
  });
  return { boards: hydratedBoards, cardData };
}

// 读某日全部看板板块(name/plateId/ztCount/netInflow + 今日涨停成员 code),并**排除看板永久删除的板块**
// (与看板同口径:getPermanentHiddenSet 黑名单,按 zsType 隔离)。供强势板块共振榜 + 热点榜资金流入共用。
async function getDayBoardsWithMembers(day, options = {}) {
  const requestedDay = isoFromCompactDate(day);
  const allowFallback = options.allowFallback !== false;
  const useDay = allowFallback ? await resolveStrategySnapshotDay(requestedDay) : requestedDay;
  // 默认三源 [6,5,7](看板/复盘等页面仍需 KPL);策略主线传 STRATEGY_ZS_TYPES=[6,5] 以剔除 KPL,避免误伤其它页面。
  const zsTypes = Array.isArray(options.zsTypes) && options.zsTypes.length ? options.zsTypes : [6, 5, 7];
  const bmap = new Map();
  const absorbPayload = async (payload, z, sourceKind = 'snapshot') => {
    let hidden; try { hidden = await getPermanentHiddenSet(z); } catch { hidden = new Set(); }
    const cardData = payload?.cardData || {};
    for (const b of (Array.isArray(payload?.boards) ? payload.boards : [])) {
      const name = String(b?.name || b?.plateName || '');
      if (!name) continue;
      const plateId = String(b?.plateId || b?.id || '');
      if (plateId && hidden.has(plateId)) continue;   // 看板永久删除的板块,共振榜也不出现
      // 未知涨停数规范为 null(不是 NaN):下游 numOrNull/回填守卫按 null 语义处理;
      // Codex #111 复核 P1——旧 Number(...??NaN) 产出 NaN,回填守卫 b.zt!=null 会把它当"已有值"跳过。
      const zt = numOrNull(b?.ztCount ?? b?.zt);
      const fundFlow = strategyBoardFundFlowForSource(b, z, {
        allowLegacyEastmoney: sourceKind === 'snapshot',
      });
      const netInflow = fundFlow.value;
      const gainPct = Number(b?.gainPct ?? b?.gain ?? b?.zf ?? b?.changePct ?? b?.涨幅 ?? NaN);
      const ztList = Array.isArray(cardData[plateId]?.ztList) ? cardData[plateId].ztList : [];
      const codes = ztList.map(x => normalizeReasonSourceCode(x?.code ?? x)).filter(Boolean);
      // 按板名去重(同名跨源塌成一条,取涨停最高者作主板→板块数/排名口径不变);
      // 但每源各留一份到 bySource,供 R2 同源配对可靠拿到东财/同花顺两组(Codex #88 点2)。
      const cur = bmap.get(name);
      const bySource = (cur && cur.bySource) || {};
      bySource[z] = {
        zsType: z,
        plateId,
        netInflow,
        netInflowMetric: fundFlow.metric,
        netInflowLegacy: fundFlow.legacy,
        gainPct,
        zt,
      };
      const winner = (!cur || (Number(zt) || 0) > (Number(cur.zt) || 0))
        ? {
            name,
            plateId,
            zsType: z,
            zt,
            netInflow,
            netInflowMetric: fundFlow.metric,
            netInflowLegacy: fundFlow.legacy,
            gainPct,
            codes,
          }
        : cur;
      winner.bySource = bySource;
      bmap.set(name, winner);
    }
  };
  for (const z of zsTypes) {
    try {
      const p = JSON.parse(await fs.readFile(snapshotPath(useDay, String(z)), 'utf8'));
      await absorbPayload(p, z, 'snapshot');
    } catch (err) { strategyMainlineDiagNoteRead(`snapshot-zs${z} ${useDay}`, err); }
  }
  let source = bmap.size ? 'snapshot' : 'none';
  if (!bmap.size && options.liveIfMissing && isChinaMarketTradingDay(requestedDay)) {
    const apiKey = await readSavedApiKey().catch(() => '');
    if (apiKey) {
      await mapLimit(zsTypes, 3, async z => {
        try {
          let hidden; try { hidden = await getPermanentHiddenSet(z); } catch { hidden = new Set(); }
          const rankBoards = await fetchBoardRankingForSnapshot(String(z), apiKey, {
            count: Number(options.liveRankCount || 0) || BOARD_RANK_FETCH_STEP,
          });
          const boards = rankBoards
            .filter(board => !hidden.has(String(board?.plateId || '')))
            .filter(isBoardGainAllowed)
            .slice(0, Number(options.boardPool || 0) || STRATEGY_MAINLINE_RISING_BOARD_LIMIT);
          const hydrated = await hydrateStrategyLiveBoardsForMembers(boards, apiKey, z, requestedDay);
          await absorbPayload(hydrated, z, 'live');
        } catch (err) { strategyMainlineDiagNoteRead(`board-rank-live zs${z} ${requestedDay}`, err); }   // 七审:实时回退失败不再空吞
      });
      if (bmap.size) source = 'live';
    }
  }
  return { useDay, boards: [...bmap.values()], source, requestedDay };
}

async function getDayThemeBoardStats(day) {
  // Owner 2026-07-15 v2:KPL(7) 不进策略辅助指标——今日热点榜每张题材卡的资金/涨幅补充值只用东财+同花顺。
  // 题材列表本身仍来自四源复盘主因库(不受此影响),这里只约束板块来源的资金/涨幅补充。
  const { useDay, boards } = await getDayBoardsWithMembers(day, { zsTypes: STRATEGY_ZS_TYPES });
  const dbPayload = await readLimitUpMainReasonDbDay(isoFromCompactDate(useDay)).catch(() => null);
  const recByCode = new Map((dbPayload?.stocks || []).map(s => [normalizeReasonSourceCode(s.code), s]).filter(([c]) => c));
  const out = new Map();
  for (const b of boards) {
    const cnt = new Map();
    for (const c of b.codes) {
      const m = recByCode.get(c);
      if (!m) continue;
      const t = String(m.finalBoardTopic || '');
      if (t) cnt.set(t, (cnt.get(t) || 0) + 1);
    }
    const dom = [...cnt.entries()].sort((a, b) => b[1] - a[1])[0];
    if (!dom) continue;
    const theme = dom[0];
    const e = out.get(theme) || {
      theme,
      boardCount: 0,
      boards: [],
      netInflow: null,
      netInflowBoard: '',
      netInflowMetric: '',
      netInflowLegacy: false,
      gainPct: null,
      gainBoard: '',
    };
    e.boardCount += 1;
    e.boards.push({
      name: b.name,
      plateId: b.plateId,
      zsType: b.zsType,
      zt: Number(b.zt) || 0,
      netInflow: Number.isFinite(Number(b.netInflow)) ? Number(b.netInflow) : null,
      netInflowMetric: b.netInflowMetric || '',
      netInflowLegacy: !!b.netInflowLegacy,
      gainPct: Number.isFinite(Number(b.gainPct)) ? Number(b.gainPct) : null,
    });
    if (Number.isFinite(Number(b.netInflow)) && (e.netInflow == null || Number(b.netInflow) > Number(e.netInflow))) {
      e.netInflow = Number(b.netInflow);
      e.netInflowBoard = b.name;
      e.netInflowMetric = b.netInflowMetric || '';
      e.netInflowLegacy = !!b.netInflowLegacy;
    }
    if (Number.isFinite(Number(b.gainPct)) && (e.gainPct == null || Number(b.gainPct) > Number(e.gainPct))) {
      e.gainPct = Number(b.gainPct);
      e.gainBoard = b.name;
    }
    out.set(theme, e);
  }
  return out;
}

// 题材→板块净流入映射:每个板块的净流入归到「其今日涨停成员的复盘主因众数(dominant)」,同题材取最大板块净流入。
// 供今日热点榜每张题材卡显示资金流入。
async function getDayThemeNetInflow(day) {
  const stats = await getDayThemeBoardStats(day);
  const themeInflow = new Map([...stats.entries()]
    .filter(([, v]) => Number.isFinite(Number(v.netInflow)))
    .map(([theme, v]) => [theme, Number(v.netInflow)]));
  return themeInflow;
}

